1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
22	
23	const basePremiumFor = (item: Item): number => {
24	  if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
25	    throw new Error(`Unknown item type: ${item.type}`);
26	  }
27	  return BASE_PREMIUM_BY_TYPE[item.type];
28	};
29	
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
32	
33	const surchargeRate = (item: Item): number =>
34	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
35	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
36	
37	const mainItemPremium = (item: Item): number => {
38	  const base = basePremiumFor(item);
39	  return base + base * surchargeRate(item);
40	};
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
43	
44	const componentGroupPremium = (group: Item[]): number =>
45	  group.length === COMPONENT_BLOCK_SIZE
46	    ? COMPONENT_BLOCK_PREMIUM
47	    : group.reduce((sum, item) => sum + basePremiumFor(item), 0);
48	
49	const groupComponentsByType = (items: Item[]): Item[][] => {
50	  const groups: Record<string, Item[]> = {};
51	  for (const item of items) {
52	    (groups[item.type] ||= []).push(item);
53	  }
54	  return Object.values(groups);
55	};
56	
57	type Customer = { yearsWithMHPCO: number; previousQuotes?: number };
58	
59	const loyaltyDiscountRate = (customer: Customer): number =>
60	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT_RATE : 0;
61	
62	const followUpDiscountRate = (customer: Customer): number =>
63	  (customer.previousQuotes ?? 0) >= 1 ? FOLLOW_UP_DISCOUNT_RATE : 0;
64	
65	const sumItemsPremium = (items: Item[], mainPremium: (item: Item) => number): number => {
66	  const components = items.filter(isComponent);
67	  const mainItems = items.filter((item) => !isComponent(item));
68	  const mainTotal = mainItems.reduce((sum, item) => sum + mainPremium(item), 0);
69	  const componentTotal = groupComponentsByType(components).reduce(
70	    (sum, group) => sum + componentGroupPremium(group),
71	    0,
72	  );
73	  return mainTotal + componentTotal;
74	};
75	
76	export function quote(customer: Customer, items: Item[]): number {
77	  const itemsTotal = sumItemsPremium(items, mainItemPremium);
78	  const policyBase = sumItemsPremium(items, basePremiumFor);
79	  const loyaltyDiscount = policyBase * loyaltyDiscountRate(customer);
80	  const followUpDiscount = policyBase * followUpDiscountRate(customer);
81	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
82	  const total = itemsTotal - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
83	  return Math.ceil(total);
84	}
85	
86	export function claim(): number {
87	  return undefined as unknown as number;
88	}
